          {
                    "regex": "addEventListener\\([^)]*\\)(?![\\s\\S]{0,200}removeEventListener)",
                    "issue": "Memory Leak: addEventListener sem correlato removeEventListener PhD.",
                    "severity": "high"
          },
          {
                    "regex": "\\.on\\([^)]*\\)(?![\\s\\S]{0,200}\\.off\\(|\\.removeListener)",
                    "issue": "Vazamento: .on() sem descadastro .off() — acúmulo garantido PhD.",
                    "severity": "high"
          },
          {
                    "regex": "setInterval\\([^)]*\\)(?![\\s\\S]{0,200}clearInterval)",
                    "issue": "Timer Leak: setInterval sem clearInterval — execuções fantasmas PhD.",
                    "severity": "high"
          },
          {
                    "regex": "new\\s+EventEmitter\\(\\)(?![\\s\\S]{0,200}setMaxListeners)",
                    "issue": "Overflow: EventEmitter sem limite restrito (setMaxListeners) PhD.",
                    "severity": "medium"
